function [SDG_L,SDG_B] = SDG(Y,bus,bl,bg,L)
%对牛顿-拉夫逊法和快速分解法的雅可比矩阵分别进行负荷节点电压变化相对于发电机节点电压变化的灵敏度矩阵计算
%% 参数读取
PQ = find(bus(:,2)==1);  %m-1个PQ节点
PV = find(bus(:,2)==2);  %n-m个PV节点
n_PQ = size(PQ,1);       %PQ节点个数
n_PV = size(PV,1);       %PV节点个数
B = imag(Y);             %导纳矩阵的虚部
n_bl = size(bl,1);       %负荷节点数
n_bg = size(bg,1);       %发电机节点数
%% 删去B中的PV节点和平衡节点，得到B1
B1 = zeros(n_PQ,n_PQ);
for i=1:n_PQ
    for j=1:n_PQ
        B1(i,j)=B(PQ(i),PQ(j));
    end
end
%% 计算LDG
LDG = zeros(n_PQ,n_PV);
for i=1:n_PQ
    for j=1:n_PV
        LDG(i,j)=B(PQ(i),PV(j));
    end
end
%% 计算灵敏度矩阵
SDG_l = -inv(L)*LDG;
SDG_b = -inv(B1)*LDG;
SDG_L = zeros(n_bl,n_bg);
SDG_B = zeros(n_bl,n_bg);
i = 1;
for j=1:n_PQ
    if bl(i)==PQ(j)
        SDG_L(i,:)=SDG_l(j,:);
        SDG_B(i,:)=SDG_b(j,:);
        i=i+1;
    end
end
